var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"집주인이 돌아왔는데 학회장이란 자는 코빼기도 비추지 않는군요.","JPN":"家の主が戻ったというのに、学会長は顔も見せないようですわね。","ENG":"The heir is back, and this so-called President doesn't even have the courtesy to greet me.","TWN":"家主都回來了，但學會長的人影連看都看不到呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"정말이지 예의를 모르는 사람이네요. 따끔하게 혼쭐을 내야겠습니다.","JPN":"本当に無礼な方です。お灸を据えてさしあげなければなりませんわね。","ENG":"How graceless and impolite she is! I'm going to teach her a lesson when I see her.","TWN":"真是不懂禮儀的人呢，我得好好教訓她一頓才行。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"헤헷. 조금만 기다려. 내가 금방 찾아서 데려올게.","JPN":"へへっ、ちょっと待っててよ。アタシが探して連れてくるからさ。","ENG":"Heh, just wait here. I'll go bring her real quick.","TWN":"嘿嘿，請稍等。我馬上就把她找來。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"도망쳐도 소용없다고 전해 두세요. 저희 가문을 모욕한 대가는 톡톡히 치러야 할 테니까요.","JPN":"逃げても無駄だとお伝えください。\\n我がマクレディー家を侮辱した対価はしっかり払っていただきますので。","ENG":"You tell her that it'd be of no use trying to run away. She's going to pay dearly for insulting my family like this.","TWN":"請幫我轉告她，就算逃跑也是沒用的。侮辱我的家族是要付出代價的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"마을도 그렇지만...... 저택도 옛날 모습 그대로네.","JPN":"町もそうだけど……屋敷も昔のままね。","ENG":"It was the same with the village, but the mansion looks just how it used to.","TWN":"村莊也是……宅邸也是以前的模樣呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 책장, 아직 남아 있었구나.","JPN":"この本棚、まだあったのね。","ENG":"This bookcase... It's still here.","TWN":"這個書櫃，也還留著啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 이 책들을 주의 깊게 살펴 보세요.","JPN":"さあ、これらの本を注意深く読んでください。","ENG":"Now, look at these books carefully.","TWN":"來，請記得要好好留意一下這些書。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"한 권씩 읽으면 흥미 위주로 쓰여진 것 같지만, 사실은 아니랍니다.","JPN":"一冊ずつ読むと興味本位で書かれた本のように見えますが、実は違います。","ENG":"If you read them one by one, they might seem to have been written just for the fun of it.","TWN":"如果妳一本一本地讀下去，可能會覺得這些書是基於興趣寫出來的，但事實並非如此。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"행간과 행간, 단어와 단어 사이에 은밀하게 숨겨진 지식들을 하나로 엮어 가다 보면......","JPN":"行間と行間、単語と単語の間に秘められた知識を繋ぎ合わせていくと……","ENG":"But by reading between the lines and sewing the fragments of knowledge hidden between words back together,","TWN":"只要把隱藏在句子和句子之間，單字和單字之間的知識串聯在一起……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"진실된 세계를 엿볼 수 있는 시야를 얻게 되죠.","JPN":"真実の世界を見ることができるようになります。","ENG":"you'll be able to gain an insight deep enough to peek through the world of truth.","TWN":"就可以獲得窺見真正世界的視野。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"지금은 이해하기 어렵겠지만, 언젠가 알게 되는 날이 올 거예요.","JPN":"今は理解できなくても、いつか分かる時が来るはずです。","ENG":"You're too young to understand now, but you'll definitely get there in the future.","TWN":"雖然現在妳還很難理解，但妳總有一天會懂的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"위조한 고문서에, 시시한 음모론 책, 철지난 공포 소설까지......","JPN":"偽造された古文書に、くだらない陰謀論、流行りの過ぎたホラー小説まで……","ENG":"Forged old manuscripts, ridiculous conspiracy theories, unpopular horror stories...","TWN":"偽造的古文書、無聊的陰謀論書籍、甚至還有過時的恐怖小說……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이런 종이 뭉치들 속에서 뭘 알아낼 수 있겠어.","JPN":"こんな紙の束から何が分かるっていうのかしら。","ENG":"What is there to get from these random collection of books?","TWN":"從這堆紙張中，到底能明白些什麼呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아버지도...... 아니, 어머니께서 해 주신 얘기였나?","JPN":"お父様も……いいえ、お母様から聞いた話だったかしら？","ENG":"Dad told me—no, was it Mom who told me that?","TWN":"父親也……不，是母親告訴我的嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하긴, 누가 말해 줬는지가 뭐 중요하겠어.","JPN":"まあ、誰から聞いたかは重要ではないけれど。","ENG":"Well, who cares who said it?","TWN":"說起來，是誰告訴我的也沒什麼重要。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데 왜 이리 춥지......? 벽난로에 불을 지펴야 하나?","JPN":"ところで、どうしてこんなに寒いの……？　暖炉に火を付けようかしら？","ENG":"Brrr, why is it so cold? Should I fire up the furnace?","TWN":"但是為什麼這麼冷……？該給壁爐生個火嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"여, 여긴 어디야? 방금 전까지 서재에 있었는데?","JPN":"こ、ここはどこ？　間違いなく書斎にいたはずなのに……","ENG":"W-where am I? I was in the library just now.","TWN":"這、這是哪裡啊？我剛才還在書房的啊？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 소리는...... 침식체......?","JPN":"この音は……侵食体……？","ENG":"This sound... Corrupted Object?","TWN":"這聲音是……侵蝕體……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>성</color><b>찬</b>이<color=#ff3636>다</color>.","JPN":"<color=#ff3636>聖</color><b>餐</b>な<color=#ff3636>り</color>。","ENG":"The <color=#ff3636>f</color><b>east</b> h<color=#ff3636>as star</color>ted.","TWN":"<color=#ff3636>是</color><b>盛</b>宴<color=#ff3636>啊</color>。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>성</b><color=#ff3636>찬의</color> 주인<color=#ff3636>이 도착</color><b>했다</b>.","JPN":"<b>聖</b><color=#ff3636>餐の</color> 主<color=#ff3636>が到着</color><b>した</b>。","ENG":"<b>The</b> <color=#ff3636>ho</color>st of the feast h<color=#ff3636>as arriv</color><b>ed</b>.","TWN":"<b>聖</b><color=#ff3636>餐</color>的主人<color=#ff3636>到</color><b>了</b>。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>불완전한</color> 지식, <b>불완</b>전한 존<color=#ff3636>재들이 성</color>찬을 통해 완<b>전해</b>지리니......","JPN":"<color=#ff3636>不完全な</color> 知識、<b>不完</b>全な存<color=#ff3636>在たちが聖</color>餐により完<b>全体と</b>なる……","ENG":"T<color=#ff3636>he feast</color> will <b>com</b>plete the imperfect <color=#ff3636>knowledge</color> and perfect the <b>imp</b>erfect beings.","TWN":"<color=#ff3636>不完整</color>的知識，<b>不完整</b>的存在將透過<color=#ff3636>盛宴</color>變得<b>完整</b>……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 저 꿈틀거리는 것들은......?","JPN":"な、何ですの？　あのグニャグニャは……？","ENG":"W-what the? What are those wriggling things?","TWN":"什、什麼？那些蠕動的東西是……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이봐요, 리벳! 침식체예요!","JPN":"リベット、来てください！　侵食体ですわ！","ENG":"Hey, Rivet! It's the C.O.s!","TWN":"喂，里維！有侵蝕體！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳! 아무도 없어요?!","JPN":"リベット！　誰かいませんか！？","ENG":"Rivet! Anyone there?","TWN":"里維！沒有人在嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識<color=#ff3636>的饗宴</color>準備好<color=#ff3636>了。宴會</color>開<b>始</b>了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 갈<color=#ff3636>구와</color> 허기<color=#ff3636>의 </color>끝이 <b>마침</b>내 도<color=#ff3636>래했</color>다.","JPN":"長い渇<color=#ff3636>きと</color> 飢え<color=#ff3636>の</color>果てが、つい<b>に訪</b>れた<color=#ff3636>の</color>だ。","ENG":"The long thir<color=#ff3636>st</color> and hung<color=#ff3636>er</color> are <b>finally</b> co<color=#ff3636>ming</color> to an end.","TWN":"長久的<color=#ff3636>渴望</color>與<color=#ff3636>饑餓</color>終於<b>到達</b>了<color=#ff3636>盡頭</color>。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>오늘</color>의 주식은 주<color=#ff3636>인의 피</color>와 <b>살이</b>니, 삼<color=#ff3636>키는 자</color>가 삼켜지<color=#ff3636>게 되리라</color>.","JPN":"<color=#ff3636>今日</color>は主の<color=#ff3636>血と</color>肉が<b>主食と</b>なり、飲<color=#ff3636>み込む者</color>が飲み込ま<color=#ff3636>れることになるだろう</color>。","ENG":"<color=#ff3636>Today</color>, the blood and <b>flesh</b> of the ho<color=#ff3636>st</color> will be on the table, and the swa<color=#ff3636>llower</color> shall become the <color=#ff3636>swallow</color>ed.","TWN":"<color=#ff3636>今天</color>的主菜是<color=#ff3636>主人的血</color>和<b>肉</b>。所以，<color=#ff3636>吞食者</color>就去<color=#ff3636>吞食</color>吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"큭......! 당신들 같은 괴물들에게 순순히 당할 줄 알고?!","JPN":"クッ……！　あなたたちのような怪物どもにそう簡単にやられてたまるものですか！！","ENG":"Ugh! You monsters won't get me!","TWN":"唔……！你們以為我會乖乖被你們這種怪物吃掉嗎？！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 맥크레디 가문의 후계자입니다! 이런 곳에서 쓰러지지 않아요!","JPN":"私はマクレディー家の後継者です！　こんなところで倒れたりしませんわ！","ENG":"The heir of the MacCready family won't fall in a place like this!","TWN":"我是麥克蕾蒂家族的繼承人！不會在這種地方倒下的！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};